defmodule WebhookProxyWeb.ProxyController do
  use WebhookProxyWeb, :controller

  def fetch(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, %HTTPoison.Response{status_code: status_code, body: body, headers: headers}} ->
        conn
        |> put_status(status_code)
        |> put_resp_headers(headers)
        |> text(body)

      {:error, %HTTPoison.Error{reason: reason}} ->
        conn
        |> put_status(:bad_gateway)
        |> json(%{error: "Failed to fetch content", reason: inspect(reason)})
    end
  end

  def fetch(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{error: "Missing required parameter: url"})
  end

  defp put_resp_headers(conn, headers) do
    Enum.reduce(headers, conn, fn {key, value}, acc ->
      put_resp_header(acc, String.downcase(key), value)
    end)
  end
end